# Module defining shape classes that use types from types_module
from types_module import Point2D, ShapeCategory, IScalable, IHasArea

# Base class for all shapes
class Shape:
    category: ShapeCategory
    center: Point2D

    def __init__(self, category: ShapeCategory, center: Point2D):
        self.category = category
        self.center = center

    @virtual
    def describe(self) -> str:
        return f"Shape at ({self.center.x}, {self.center.y})"

    def get_category_name(self) -> str:
        return self.category.name

# Circle implements both interfaces
class Circle(Shape, IScalable, IHasArea):
    radius: float

    def __init__(self, center: Point2D, radius: float):
        super().__init__(ShapeCategory.BASIC, center)
        self.radius = radius

    @override
    def describe(self) -> str:
        return f"Circle with radius {self.radius} at ({self.center.x}, {self.center.y})"

    def get_area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def scale(self, factor: float) -> None:
        self.radius = self.radius * factor

# Rectangle also implements both interfaces
class Rectangle(Shape, IScalable, IHasArea):
    width: float
    height: float

    def __init__(self, center: Point2D, width: float, height: float):
        super().__init__(ShapeCategory.COMPLEX, center)
        self.width = width
        self.height = height

    @override
    def describe(self) -> str:
        return f"Rectangle {self.width}x{self.height} at ({self.center.x}, {self.center.y})"

    def get_area(self) -> float:
        return self.width * self.height

    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

# Factory functions
def create_unit_circle() -> Circle:
    return Circle(Point2D(0.0, 0.0), 1.0)

def create_default_rectangle() -> Rectangle:
    return Rectangle(Point2D(0.0, 0.0), 2.0, 3.0)

