# Utility module with helper functions
from types_module import Point2D
from shapes_module import Circle, Rectangle, IHasArea

def moved_point(point: Point2D, dx: float, dy: float) -> Point2D:
    return Point2D(point.x + dx, point.y + dy)

def sum_areas(shapes: list[IHasArea]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.get_area()
    return total
